+import type { AnyColumn, GetColumnData } from '~/column.ts';
+import { SQL, sql, type SQLChunk, type SQLWrapper } from '../sql.ts';
+
+export type WindowOrderBy = SQLWrapper | readonly SQLWrapper[];
+
+export interface WindowSpec {
+	partitionBy?: WindowOrderBy;
+	orderBy?: WindowOrderBy;
+	frame?: WindowFrame;
+}
+
+type FrameBoundaryKind = 'unbounded preceding' | 'preceding' | 'current row' | 'following' | 'unbounded following';
+
+export interface FrameBoundary {
+	readonly kind: FrameBoundaryKind;
+	readonly offset?: number;
+}
+
+export interface WindowFrame {
+	readonly type: 'rows' | 'range';
+	readonly from: FrameBoundary;
+	readonly to: FrameBoundary;
+}
+
+const makeBoundary = (kind: FrameBoundaryKind, offset?: number): FrameBoundary => ({ kind, offset });
+
+export const unboundedPreceding = makeBoundary('unbounded preceding');
+export const currentRow = makeBoundary('current row');
+export const unboundedFollowing = makeBoundary('unbounded following');
+
+function assertFrameOffset(name: 'preceding' | 'following', value: number): void {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${name}() expects a non-negative integer, received ${value}`);
+	}
+}
+
+export function preceding(value: number): FrameBoundary {
+	assertFrameOffset('preceding', value);
+	return makeBoundary('preceding', value);
+}
+
+export function following(value: number): FrameBoundary {
+	assertFrameOffset('following', value);
+	return makeBoundary('following', value);
+}
+
+function boundaryOrder(boundary: FrameBoundary): number {
+	switch (boundary.kind) {
+		case 'unbounded preceding': return Number.NEGATIVE_INFINITY;
+		case 'preceding': return -boundary.offset!;
+		case 'current row': return 0;
+		case 'following': return boundary.offset!;
+		case 'unbounded following': return Number.POSITIVE_INFINITY;
+	}
+}
+
+function frame(type: WindowFrame['type'], spec: { from: FrameBoundary; to: FrameBoundary }): WindowFrame {
+	if (boundaryOrder(spec.from) > boundaryOrder(spec.to)) {
+		throw new Error('Window frame from boundary must not be ordered after to boundary');
+	}
+	return { type, ...spec };
+}
+
+export function rows(spec: { from: FrameBoundary; to: FrameBoundary }): WindowFrame {
+	return frame('rows', spec);
+}
+
+export function range(spec: { from: FrameBoundary; to: FrameBoundary }): WindowFrame {
+	return frame('range', spec);
+}
+
+function renderBoundary(boundary: FrameBoundary): SQL {
+	return boundary.offset === undefined ? sql.raw(boundary.kind) : sql.raw(`${boundary.offset} ${boundary.kind}`);
+}
+
+function list(value: WindowOrderBy): readonly SQLWrapper[] {
+	return Array.isArray(value) ? value : [value];
+}
+
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const chunks: SQLChunk[] = [];
+	if (spec.partitionBy) chunks.push(sql`partition by ${sql.join([...list(spec.partitionBy)], sql`, `)}`);
+	if (spec.orderBy) chunks.push(sql`order by ${sql.join([...list(spec.orderBy)], sql`, `)}`);
+	if (spec.frame) {
+		chunks.push(sql`${sql.raw(spec.frame.type)} between ${renderBoundary(spec.frame.from)} and ${renderBoundary(spec.frame.to)}`);
+	}
+	return sql.join(chunks, sql` `);
+}
+
+export class WindowFunction<T> implements SQLWrapper {
+	constructor(private readonly expression: SQL<T>) {}
+
+	over(spec: WindowSpec | string = {}): SQL<T> {
+		return typeof spec === 'string'
+			? sql`${this.expression} over ${sql.identifier(spec)}`
+			: sql`${this.expression} over (${buildWindowSpec(spec)})`;
+	}
+
+	getSQL(): SQL<T> {
+		return this.expression;
+	}
+}
+
+type ExpressionData<T extends SQLWrapper> = T extends AnyColumn ? GetColumnData<T> : T extends SQL<infer TValue> ? TValue : unknown;
+
+function windowFunction<T>(name: string, args: SQLChunk[] = []): WindowFunction<T> {
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})` as SQL<T>);
+}
+
+function positionalArgument(name: 'ntile' | 'nthValue', value: number): SQL {
+	if (!Number.isInteger(value) || value <= 0) {
+		throw new Error(`${name}() expects a positive integer, received ${value}`);
+	}
+	return sql.raw(String(value));
+}
+
+export function rowNumber(): WindowFunction<number> { return windowFunction('row_number'); }
+export function rank(): WindowFunction<number> { return windowFunction('rank'); }
+export function denseRank(): WindowFunction<number> { return windowFunction('dense_rank'); }
+export function ntile(buckets: number): WindowFunction<number> { return windowFunction('ntile', [positionalArgument('ntile', buckets)]); }
+export function percentRank(): WindowFunction<number> { return windowFunction('percent_rank'); }
+export function cumeDist(): WindowFunction<number> { return windowFunction('cume_dist'); }
+
+export function lag<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null>;
+export function lag<T extends SQLWrapper>(expression: T, offset: number): WindowFunction<ExpressionData<T> | null>;
+export function lag<T extends SQLWrapper, TDefault>(expression: T, offset: number | undefined, defaultValue: TDefault | SQLWrapper): WindowFunction<Exclude<ExpressionData<T>, null> | TDefault>;
+export function lag(expression: SQLWrapper, offset?: number, defaultValue?: unknown): WindowFunction<unknown> {
+	const args: SQLChunk[] = [expression];
+	if (offset !== undefined) args.push(sql.raw(String(offset)));
+	if (defaultValue !== undefined) args.push(defaultValue as SQLChunk);
+	return windowFunction('lag', args);
+}
+
+export function lead<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null>;
+export function lead<T extends SQLWrapper>(expression: T, offset: number): WindowFunction<ExpressionData<T> | null>;
+export function lead<T extends SQLWrapper, TDefault>(expression: T, offset: number | undefined, defaultValue: TDefault | SQLWrapper): WindowFunction<Exclude<ExpressionData<T>, null> | TDefault>;
+export function lead(expression: SQLWrapper, offset?: number, defaultValue?: unknown): WindowFunction<unknown> {
+	const args: SQLChunk[] = [expression];
+	if (offset !== undefined) args.push(sql.raw(String(offset)));
+	if (defaultValue !== undefined) args.push(defaultValue as SQLChunk);
+	return windowFunction('lead', args);
+}
+
+export function firstValue<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null> { return windowFunction('first_value', [expression]); }
+export function lastValue<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null> { return windowFunction('last_value', [expression]); }
+export function nthValue<T extends SQLWrapper>(expression: T, position: number): WindowFunction<ExpressionData<T> | null> { return windowFunction('nth_value', [expression, positionalArgument('nthValue', position)]); }
+
+export function windowSum(expression: SQLWrapper): WindowFunction<string | null> { return windowFunction('sum', [expression]); }
+export function windowAvg(expression: SQLWrapper): WindowFunction<string | null> { return windowFunction('avg', [expression]); }
+export function windowMin<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null> { return windowFunction('min', [expression]); }
+export function windowMax<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null> { return windowFunction('max', [expression]); }
+export function windowCount(expression?: SQLWrapper): WindowFunction<number> { return windowFunction('count', [expression ?? sql.raw('*')]); }
